import { useMutation } from 'react-query';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { SmartyAddress } from '@ui/components/formControls/compositions/SmartyAddressInput/types';
import { makeSearchParams } from '@utils';

type UseVerifySmartyAddressProps = {
  accountSlug?: string;
  address: SmartyAddress;
};

export const useVerifySmartyAddress = () => {
  const { refreshCache } = useCacheHelper(resourceKeys.smartyAddressVerify);

  const mutation = useMutation<SmartyAddress[], IErrorResponse, UseVerifySmartyAddressProps>(
    async ({ accountSlug, address }) => {
      const params = makeSearchParams({
        accountSlug,
        city: address?.city ?? '',
        state: address?.state ?? '',
        street: address?.street_line,
        street2: address?.secondary ?? '',
        zipcode: address?.zipcode ?? '',
      });

      if (!address || !accountSlug) {
        return [];
      }

      return new ApiClient({ namespace: 'public' }).get<SmartyAddress[]>(
        `/smarty/verify?${params.toString()}`
      );
    },
    {
      onSuccess: () => {
        return refreshCache('');
      },
    }
  );

  return {
    error: mutation.error,
    isError: mutation.isError,
    isLoading: mutation.isLoading,
    verifyAddress: mutation.mutateAsync,
  };
};
